  // (i.e., ~C2 is a power of 2). The condition (X + C1) & C2 == 0 means (X + C1)
  // can only have the bit set where C2 has a zero, so (X + C1) ∈ {0, 1<<K}.
  // Therefore X ∈ {-C1, (1<<K) - C1}. If (-C1) and (1<<K)-C1 differ only in
  // bit K, we can simplify to X & C2 == (-C1) & C2, then use KnownBits to
  // eliminate bits that are already determined.
  if (C.isZero() && Cmp.isEquality()) {
    Value *X;
    const APInt *C1, *C2;
    if (match(And, m_OneUse(m_c_And(m_OneUse(m_NSWAdd(m_Value(X), m_APInt(C1))),
                                    m_APInt(C2)))) &&
        (~(*C2)).isPowerOf2()) {
      unsigned K = (~(*C2)).logBase2();
      APInt M = APInt::getOneBitSet(C2->getBitWidth(), K);
      APInt NegC1 = -(*C1);
      // Check that bit K of -C1 is 0, so -C1 and -C1 + M differ only in bit K.
      if ((NegC1 & M).isZero()) {
        APInt Expected = NegC1 & *C2;
        // Use KnownBits to simplify the condition X & C2 == Expected.
        KnownBits KnownX = computeKnownBits(X, /*Depth=*/0, And);
        // If Expected has a 1 where X is known to have 0, always false.
        if ((Expected & KnownX.Zero).getBoolValue())
          return replaceInstUsesWith(
              Cmp, ConstantInt::get(Cmp.getType(), Pred == ICmpInst::ICMP_EQ));
        // If Expected has a 0 (within the mask) where X is known to have 1,
        // always false.
        if (((~Expected & *C2) & KnownX.One).getBoolValue())
          return replaceInstUsesWith(
              Cmp, ConstantInt::get(Cmp.getType(), Pred == ICmpInst::ICMP_EQ));
        // Determine which bits of the mask are already satisfied.
        APInt SatisfiedBits = (Expected & KnownX.One) |
                              ((~Expected & *C2) & KnownX.Zero);
        APInt RequiredMask = *C2 & ~SatisfiedBits;
        if (RequiredMask.isZero())
          return replaceInstUsesWith(
              Cmp, ConstantInt::get(Cmp.getType(), Pred == ICmpInst::ICMP_NE));
        // Create simplified comparison.
        Value *NewAnd =
            Builder.CreateAnd(X, ConstantInt::get(X->getType(), RequiredMask));
        return new ICmpInst(Pred, NewAnd, ConstantInt::get(NewAnd->getType(),
                                                           Expected & RequiredMask));
      }
    }
  }

  return nullptr;
