def verify_test_group(repro: bool, input, type: str):
    """批量执行测试组（带 commands + test_body 的标准样本格式）。"""
    test_res = []
    overall_test_res = not repro
    for test in input:
        print("test: ", test)
        file = test["file"]
        commands = test["commands"]
        tests = test["tests"]
        for subtest in tests:
            name = subtest["test_name"]
            body = subtest["test_body"]
            for args in commands:
                res, log = verify_dispatch(
                    repro,
                    body,
                    args,
                    type,
                    subtest.get("additional_args"),
                    subtest.get("lli_expected_out"),
                    subtest.get("source_program"),
                    subtest.get("expect_optimized_program"),
                )
                test_res.append(
                    {
                        "file": file,
                        "args": args,
                        "name": name,
                        "body": body,
                        "result": res,
                        "log": log,
                    }
                )
                if _test_log_has_infra_error(log):
                    return (False, test_res)
                if repro:
                    overall_test_res = overall_test_res or res
                else:
                    overall_test_res = overall_test_res and res
    return (overall_test_res, test_res)

    """提取 fast-check 中的基础设施失败条目。"""
    failures = []
    if not isinstance(log, list):
        return failures
    for test_log in log:
        data = test_log.get("log", {})
        if not isinstance(data, dict):
            continue
        if data.get("infra_error"):
            failures.append(
                {
                    "name": test_log.get("name", "unknown"),
                    "reason": data.get("infra_reason", "infra_error"),
                    "detail": data.get("alive2", {}).get("log", data.get("log", "")),
                }
            )
            continue
        alive2 = data.get("alive2", {})
        if isinstance(alive2, dict) and alive2.get("infra_error"):
            failures.append(
                {
                    "name": test_log.get("name", "unknown"),
                    "reason": alive2.get("infra_reason", "alive2_infra_error"),
                    "detail": alive2.get("log", ""),
                }
            )
    return failures


def normalize_build_errors(log) -> str:
    """从构建日志中提取关键错误行。"""
    if isinstance(log, list):
        return json.dumps(log, indent=2)[:MAX_LOG_SIZE]
    text = str(log)
    pattern = re.compile(
        r"(llvm-project/llvm/[^\n]+error:[^\n]+(?:\n[ ]*\d+\s*\|[^\n]*)?)"
    )
    matches = pattern.findall(text)
    if matches:
        result = "\n".join(matches)
        if len(result) > MAX_LOG_SIZE:
            return result[:MAX_LOG_SIZE] + "\n<Truncated>..."
        return result
    if len(text) > MAX_LOG_SIZE:
        return text[:MAX_LOG_SIZE] + "\n<Truncated>..."
    return text


def format_test_results(log) -> str:
    """格式化快速检查结果为人类可读文本。"""
    if not isinstance(log, list):
        text = str(log)
        if len(text) > MAX_LOG_SIZE:
            return text[:MAX_LOG_SIZE] + "\n<Truncated>..."
        return text

    output = []
    for test_log in log:
        name = test_log.get("name", "unknown")
        result = test_log.get("result", False)
        status = "PASS" if result else "FAIL"
        output.append(f"[{status}] {name}")

        if not result:
            log_data = test_log.get("log", {})
            if isinstance(log_data, dict):
                if log_data.get("infra_error"):
                    reason = log_data.get("infra_reason", "infra_error")
                    output.append(f"  Infra error: {reason}")
                # 输出 source / expected / current IR 对比
                src = log_data.get("source_program", "")
                exp = log_data.get("expect_optimized_program", "")
                cur = log_data.get("current_optimized_program", "")
                if src:
                    output.append(f"  Source program:\n```llvm\n{src}\n```")
                if exp:
                    output.append(f"  Expected optimized:\n```llvm\n{exp}\n```")
                if cur:
                    output.append(f"  Current optimized:\n```llvm\n{cur}\n```")

                # Alive2 结果
                alive2 = log_data.get("alive2", {})
                if isinstance(alive2, dict):
                    if alive2.get("infra_error"):
                        output.append(
                            f"  Alive2 infra error: {alive2.get('infra_reason', 'unknown')}"
                        )
                    a2log = alive2.get("log", "")
                    if a2log and "0 incorrect" not in str(a2log):
                        a2_text = str(a2log)
                        if len(a2_text) > 2000:
                            a2_text = a2_text[:2000] + "\n<Truncated>..."
                        output.append(f"  Alive2 log:\n{a2_text}")
            else:
                text = str(log_data)
                if len(text) > 2000:
                    text = text[:2000] + "\n<Truncated>..."
                output.append(f"  Log: {text}")

    return "\n".join(output)


def main():
    issue_id = get_env_or_die("AGENT_ISSUE_ID")
    basemodel_cutoff = os.environ.get("LAB_LLM_BASEMODEL_CUTOFF", "1970-12-31Z")
    max_build_jobs = int(os.environ.get("LAB_MAX_BUILD_JOBS", os.cpu_count()))

    env = Env(issue_id, basemodel_cutoff, max_build_jobs=max_build_jobs)

    print("=== Building LLVM + Fast Check ===")
    print(f"LLVM dir: {llvm_helper.llvm_dir}")
    print(f"Build dir: {llvm_helper.llvm_build_dir}")
    print()

    res, log = env.check_fast(skip_build=False)

    if res:
        print("✓ BUILD SUCCESS + FAST CHECK PASSED")
        print()
        print(format_test_results(log))
    else:
        # 判断是构建失败还是测试失败
        if env.build_failure_count > 0 and not isinstance(log, list):
            print("✗ BUILD FAILED")
            print()
            print(normalize_build_errors(log))
        else:
            print("✓ BUILD SUCCESS")
            print("✗ FAST CHECK FAILED")
            print()
            infra_failures = collect_infra_failures(log)
            if infra_failures:
                print("! INFRA FAILURE DETECTED (toolchain/runtime)")
                for item in infra_failures[:3]:
                    print(f"  - {item['name']}: {item['reason']}")
                print()
            print(format_test_results(log))


if __name__ == "__main__":
    main()

def check_fast(self, skip_build=False):
    """快速检查：build + verify_test_group，不跑 llvm-lit。"""
    with TimeCompensationGuard(self):
        self.fast_check_count += 1
        if not skip_build:
            res, reason = self.build()
            if not res:
                return (False, reason)
        else:
            self.build_count += 1
        res, log = self._verify_fast_group(repro=False)
        if not res:
            return (False, log)
        self.fast_check_pass = True
        return (True, log)

def _verify_fast_group(self, *, repro: bool):
    """执行与 pipeline 一致的 fast-check 测试组验证。

    统一走 llvm_helper.verify_test_group_orig：
    - commands 非空时回退到 verify_dispatch（兼容旧数据格式）；
    - commands 为空时按 source/expect IR 做 alive2 + cost 校验。
    """
    hints = self.data.get("hints") or {}
    return llvm_helper.verify_test_group_orig(
        repro=repro,
        input_tests=self.data["tests"],
        type_str=self.bug_type,
        component_list=hints.get("components"),
    )

def verify_test_group_orig(repro: bool, input_tests, type_str: str, component_list):
    """验证 dataset-orig 风格测试（commands 为空，靠 source/expect IR 比较）。

    行为：
    1. 根据组件推断 opt pass；
    2. 对 source_program 跑 opt 得到 current_optimized_program；
    3. 用 alive2 + cost 判断优化正确性与收益（无 FileCheck）。
    """
    test_res = []
    overall_test_res = not repro
    if not component_list:
        component_list = ["InstCombine"]
    component = component_list[0] if component_list else "InstCombine"
    pass_name = _COMPONENT_TO_OPT_PASS.get(component, "instcombine")
    opt_base = [os.path.join(llvm_build_dir, "bin/opt"), "--passes=" + pass_name, "-S"]

    for test in input_tests:
        print("test: ", test)
        file = test["file"]
        commands = test.get("commands", [])
        tests = test["tests"]
        if commands:
            # Fallback to normal verify if commands present
            for subtest in tests:
                body = subtest.get("test_body", "")
                for args in commands:
                    res, log = verify_dispatch(
                        repro,
                        body,
                        args,
                        type_str,
                        subtest.get("additional_args"),
                        subtest.get("lli_expected_out"),
                        subtest.get("source_program"),
                        subtest.get("expect_optimized_program"),
                    )
                    test_res.append(
                        {
                            "file": file,
                            "args": args,
                            "name": subtest["test_name"],
                            "body": body,
                            "result": res,
                            "log": log,
                        }
                    )
                    if _test_log_has_infra_error(log):
                        return (False, test_res)
                    if repro:
                        overall_test_res = overall_test_res or res
                    else:
                        overall_test_res = overall_test_res and res
            continue

        # commands empty: run opt on source_program, check alive2 + cost only (no FileCheck)
        for subtest in tests:
            name = subtest["test_name"]
            source_program = subtest.get("source_program") or ""
            expect_optimized_program = subtest.get("expect_optimized_program") or ""
            if not source_program or not expect_optimized_program:
                test_res.append(
                    {
                        "file": file,
                        "args": "(no FileCheck)",
                        "name": name,
                        "body": "",
                        "result": False,
                        "log": {
                            "error": "missing source_program or expect_optimized_program"
                        },
                    }
                )
                overall_test_res = False
                continue
            try:
                print(f"opt_base: {opt_base}")
                out = subprocess.run(
                    opt_base,
                    input=source_program.encode(),
                    timeout=10.0,
                    capture_output=True,
                    check=True,
                )
                output = out.stdout.decode()
                new_input = copy_triple(source_program, out.stdout)
                new_input = copy_datalayout(new_input, out.stdout)
                additional_args = subtest.get("additional_args")
                res_alive2, log_alive2 = alive2_check(
                    new_input, output, additional_args
                )
                current_optimized_program = output.removeprefix(
                    "; ModuleID = '<stdin>'\nsource_filename = \"<stdin>\"\n"
                ).removeprefix("\n")
                res_cost, log_cost = cost_check(
                    source_program, expect_optimized_program, current_optimized_program
                )
                log = {
                    "alive2": log_alive2,
                    "cost": log_cost,
                    "source_program": source_program,
                    "expect_optimized_program": expect_optimized_program,
                    "current_optimized_program": current_optimized_program,
                }
                if _alive2_log_is_infra(log_alive2):
                    log["infra_error"] = True
                    log["infra_reason"] = log_alive2.get("infra_reason")
                    res = False
                    test_res.append(
                        {
                            "file": file,
                            "args": "(no FileCheck)",
                            "name": name,
                            "body": "",
                            "result": False,
                            "log": log,
                        }
                    )
                    return (False, test_res)
                if repro:
                    res = res_alive2 and not res_cost
                else:
                    res = res_alive2 and res_cost
                print(f"res: {res}")
                print(f"res_alive2: {res_alive2}")
                print(f"res_cost: {res_cost}")
                test_res.append(
                    {
                        "file": file,
                        "args": "(no FileCheck)",
                        "name": name,
                        "body": "",
                        "result": res,
                        "log": log,
                    }
                )
                if repro:
                    overall_test_res = overall_test_res or res
                else:
                    overall_test_res = overall_test_res and res
            except Exception as e:
                err_log = str(e)
                if hasattr(e, "stderr") and e.stderr:
                    err_log += "\n" + decode_output(e.stderr)
                if hasattr(e, "stdout") and e.stdout:
                    err_log += "\n" + decode_output(e.stdout)
                test_res.append(
                    {
                        "file": file,
                        "args": "(no FileCheck)",
                        "name": name,
                        "body": "",
                        "result": False,
                        "log": {"error": err_log},
                    }
                )
                overall_test_res = False
    return (overall_test_res, test_res)

def check_full(self):
    """完整检查：build + verify_test_group + verify_lit。"""
    with TimeCompensationGuard(self):
        self.full_check_count += 1
        res, reason = self.build()
        if not res:
            return (False, reason)
        res, log = self._verify_fast_group(repro=False)
        self.check_fast_log.append(log)
        if not res:
            return (False, log)
        self.fast_check_pass = True
        res, log = llvm_helper.verify_lit(
            test_commit=self.test_commit,
            dirs=self.data["lit_test_dir"],
            max_test_jobs=self.max_build_jobs,
        )
        self.check_full_log.append(log)
        if not res:
            return (False, log)
        self.full_check_pass = True
        return (True, log)
